import React, { useEffect, useState } from 'react';
import { View, Button, Platform } from 'react-native';
import * as RNIap from 'react-native-iap';
import InAppPurchase from 'react-native-payments';
import * as SecureStore from 'expo-secure-store';

const productIds = Platform.select({
  ios: ['com.example.app.product1'],
  android: ['com.example.app.product1']
});

const PaymentModule = () => {
  const [initialized, setInitialized] = useState(false);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        await RNIap.initConnection();
        await InAppPurchase.setupCardForm();
        setInitialized(true);
      } catch (error) {
        console.warn('Initialization error', error);
      }
    })();
    return () => {
      RNIap.endConnection();
    };
  }, []);

  const handlePurchase = async () => {
    if (!initialized) return;
    try {
      setLoading(true);
      const product = productIds[0];
      const purchase = await RNIap.requestPurchase(product);
      await RNIap.finishTransaction(purchase);
      await SecureStore.setItemAsync('receiptData', JSON.stringify(purchase));
    } catch (error) {
      console.warn('Purchase error', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDigitalWallet = async () => {
    try {
      setLoading(true);
      const paymentRequest = {
        countryCode: 'US',
        currencyCode: 'USD',
        supportedMethods: ['apple-pay', 'android-pay'],
        paymentMethodTokenizationParameters: {
          tokenizationType: 'PAYMENT_GATEWAY',
          parameters: {
            gateway: 'example',
            gatewayMerchantId: 'exampleMerchantId'
          }
        },
        lineItems: [
          {
            label: 'Test Item',
            amount: '1.00'
          }
        ],
        total: {
          label: 'Test Purchase',
          amount: '1.00'
        }
      };
      const token = await InAppPurchase.show(paymentRequest);
      await SecureStore.setItemAsync('walletTransactionToken', JSON.stringify(token));
    } catch (error) {
      console.warn('Digital wallet error', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <View>
      <Button
        title="Buy Product"
        disabled={loading || !initialized}
        onPress={handlePurchase}
      />
      <Button
        title="Pay with Digital Wallet"
        disabled={loading || !initialized}
        onPress={handleDigitalWallet}
      />
    </View>
  );
};

export default PaymentModule;